 #!/usr/bin/env python3

 import json
 import re
 import sys
 from pathlib import Path


 COPILOT_TRAILER = "Co-authored-by: Copilot <223556219+Copilot@users.noreply.github.com>"
 REQUIRED_HEADINGS = [
